body.script:

(function() {
    'use strict';

    // ── Debug logger ──────────────────────────────────────
    const log  = (...a) => console.log('[LiveTracking]', ...a);
    const warn = (...a) => console.warn('[LiveTracking]', ...a);
    const err  = (...a) => console.error('[LiveTracking]', ...a);

    const root = document.getElementById('trackingRoot');
    if (!root) return;

    const isOwner   = root.dataset.isOwner   === '1';
    const trackerId = root.dataset.trackerId;

    // State is driven by the SERVER (DB) — not by what this tab thinks.
    // Every 2 s we poll /status/:id to get the real is_tracking flag.
    // This means: if another tab stops tracking, this tab reflects it too.
    const state = {
        tracking: false,          // mirrors DB is_tracking
        gpsIntervalId: null,      // setInterval for GPS send
        timerIntervalId: null,    // setInterval for clock
        trackingStart: null,      // Date.now() when this tab started sending
        lastLat: null,
        lastLng: null,
        totalDistance: parseFloat(root.dataset.distance || '0'),
        consecutiveErrors: 0,
        userMovedMap: false,      // true after user manually pans/zooms → disable auto-pan
        mapInitialised: false,
    };

    const $ = id => document.getElementById(id);

    // ── Map ───────────────────────────────────────────────
    let liveMap      = null;
    let liveMarker   = null;
    let livePolyline = null;
    let livePath     = [];

    function initLiveMap() {
        if (state.mapInitialised || typeof L === 'undefined') return;
        const el = $('liveMap');
        if (!el) return;
        liveMap = L.map('liveMap', { zoomControl: true }).setView([23.7701, 90.4254], 14);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '', maxZoom: 19,
        }).addTo(liveMap);

        // Detect manual pan / zoom → disable auto-follow
        liveMap.on('dragstart zoomstart', () => {
            state.userMovedMap = true;
            log('User moved map — auto-pan disabled');
        });
        state.mapInitialised = true;
        log('Map initialised');
    }

    // Push a GPS fix to the map WITHOUT auto-panning unless the
    // user has never moved the map (first fix centres the view once).
    function pushToMap(lat, lng, firstFix) {
        if (!liveMap) initLiveMap();
        if (!liveMap) return;

        livePath.push([lat, lng]);

        if (livePolyline) {
            livePolyline.addLatLng([lat, lng]);
        } else {
            livePolyline = L.polyline(livePath, { color: '#3b82f6', weight: 4 }).addTo(liveMap);
        }

        if (!liveMarker) {
            liveMarker = L.circleMarker([lat, lng], {
                radius: 10, color: '#fff', fillColor: '#ef4444', fillOpacity: 1, weight: 3,
            }).addTo(liveMap);
        } else {
            liveMarker.setLatLng([lat, lng]);
        }

        // Only auto-pan on the very first GPS fix (centres the map),
        // never again unless the user explicitly resets.
        if (firstFix && !state.userMovedMap) {
            liveMap.setView([lat, lng], 16, { animate: true });
            log('First fix — map centred on salesperson at zoom 16');
        }

        setTimeout(() => liveMap.invalidateSize(), 100);
    }

    // ── Helpers ───────────────────────────────────────────
    const formatDuration = ms => {
        const s = Math.floor(ms / 1000);
        return `${String(Math.floor(s / 60)).padStart(2,'0')}:${String(s % 60).padStart(2,'0')}`;
    };

    const updateStatusMessage = (message, type = 'info') => {
        const msgDiv    = $('statusMessage');
        const statusText = $('statusText');
        const statusDot  = $('statusDot');
        if (!msgDiv || !statusText) return;
        statusText.textContent = message;
        msgDiv.className = 'status-message ' + type;
        if (statusDot) {
            statusDot.className = 'status-dot ' + (state.tracking ? 'live' : 'offline');  // offline when stopped
        }
    };

    const setStartBtn = disabled => { const b = $('startButton'); if (b) b.disabled = disabled; };
    const setStopBtn  = disabled => { const b = $('stopButton');  if (b) b.disabled = disabled; };

    const postJson = async (url, payload) => {
        const res = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload || {}),
            credentials: 'same-origin',
            keepalive: true,
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
    };

    const haversine = (lat1, lon1, lat2, lon2) => {
        const R = 6371, dLat = (lat2-lat1)*Math.PI/180, dLon = (lon2-lon1)*Math.PI/180;
        const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
        return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    };

    // ── GPS: high-accuracy options ────────────────────────
    // enableHighAccuracy: true requests GPS hardware (not cell/WiFi).
    // maximumAge: 0       disables cached positions (always fresh).
    // timeout: 15000      gives GPS chip enough time to get a fix.
    // ══════════════════════════════════════════════════════
    // GPS ARCHITECTURE
    // ──────────────────────────────────────────────────────
    // Each tick calls getCurrentPosition() directly.
    // This guarantees a FRESH position reading every 2 s
    // regardless of movement — no stale cached position.
    //
    // Why NOT watchPosition?
    //   On mobile, watchPosition fires only on OS movement
    //   events. Stationary users get zero callbacks, so
    //   latestPos stays stale and logs stop being written.
    //
    // Why getCurrentPosition every tick?
    //   maximumAge:0 forces a fresh hardware reading.
    //   timeout:4000 ensures it finishes before the next tick.
    //   This is the only reliable way to log every 2 s.
    //
    // Geocoding (reverse lookup) is done SEPARATELY every 30 s
    // via /geocode — never inside update_live_location — so a
    // slow Nominatim response never blocks log creation.
    // ══════════════════════════════════════════════════════

    const GEO_OPTS_TICK = {
        enableHighAccuracy: true,
        timeout: 4000,       // must finish before next 2 s tick
        maximumAge: 0,       // ALWAYS fresh — never cached
    };

    let sendIntervalId  = null;
    let tickBusy        = false;   // prevent overlapping ticks
    let geocodeIntervalId = null;
    let lastGeocodeLat  = null;
    let lastGeocodeLng  = null;

    // ── Single tick: get fresh GPS fix then POST ──────────
    function doTick() {
        if (!state.tracking || !isOwner) return;
        if (tickBusy) {
            log('doTick: previous tick still running — skipping');
            return;
        }
        tickBusy = true;

        navigator.geolocation.getCurrentPosition(
            async function(pos) {
                const lat = pos.coords.latitude;
                const lng = pos.coords.longitude;
                const acc = pos.coords.accuracy;

                log('doTick: GPS lat=%.6f lng=%.6f acc=%.1fm', lat, lng, acc);
                if ($('accuracyValue')) $('accuracyValue').textContent = acc.toFixed(1) + ' m';

                const isFirst = state.lastLat === null;
                // tickDelta = distance moved since last tick (km).
                // We send only the INCREMENT, not cumulative total.
                // Server adds this to its own running total.
                let tickDelta = 0;
                if (!isFirst)
                    tickDelta = haversine(state.lastLat, state.lastLng, lat, lng);
                state.totalDistance += tickDelta;
                state.lastLat = lat;
                state.lastLng = lng;

                try {
                    const result = await postJson('/salesperson_tracking/update', {
                        latitude:   lat,
                        longitude:  lng,
                        accuracy:   acc,
                        distance:   tickDelta,   // per-tick delta, NOT cumulative
                        tracker_id: trackerId,
                    });
                    state.consecutiveErrors = 0;

                    if ($('latitudeValue'))  $('latitudeValue').textContent  = lat.toFixed(6);
                    if ($('longitudeValue')) $('longitudeValue').textContent = lng.toFixed(6);
                    if ($('lastSeenValue'))  $('lastSeenValue').textContent  = result.last_seen || new Date().toLocaleTimeString();
                    if ($('kpiDistance') && result.total_distance_km != null)
                        $('kpiDistance').textContent = parseFloat(result.total_distance_km).toFixed(1);

                    pushToMap(lat, lng, isFirst);
                    updateStatusMessage('Tracking Active — updating every 2 seconds', 'info');

                } catch(e) {
                    state.consecutiveErrors++;
                    err('doTick POST error (%d/5): %s', state.consecutiveErrors, e.message);
                    updateStatusMessage('Update error: ' + e.message, 'error');
                    if (state.consecutiveErrors >= 5) {
                        warn('5 consecutive errors — stopping');
                        stopSendInterval();
                    }
                } finally {
                    tickBusy = false;
                }
            },
            function(geoErr) {
                tickBusy = false;
                const msgs = {
                    1: 'Location access denied — enable GPS in browser settings.',
                    2: 'GPS signal unavailable.',
                    3: 'GPS timeout — will retry next tick.',
                };
                const msg = msgs[geoErr.code] || ('GPS error: ' + geoErr.message);
                err('doTick GPS error code=%d: %s', geoErr.code, msg);
                updateStatusMessage(msg, 'error');
            },
            GEO_OPTS_TICK
        );
    }

    function startSendInterval() {
        if (sendIntervalId !== null) return;
        tickBusy = false;
        doTick();   // fire immediately
        sendIntervalId = setInterval(doTick, 2000);
        log('sendInterval started (every 2 s)');

        // Geocode every 30 s — separate from log updates
        geocodeIntervalId = setInterval(async () => {
            if (!state.tracking || state.lastLat === null) return;
            if (Math.abs(state.lastLat - (lastGeocodeLat || 0)) < 0.0005 &&
                Math.abs(state.lastLng - (lastGeocodeLng || 0)) < 0.0005 &&
                lastGeocodeLat !== null) return;  // haven't moved enough
            lastGeocodeLat = state.lastLat;
            lastGeocodeLng = state.lastLng;
            try {
                const r = await postJson('/salesperson_tracking/geocode', {
                    latitude: state.lastLat, longitude: state.lastLng,
                    tracker_id: trackerId,
                });
                if (r.ok && r.location_name && $('locationNameValue'))
                    $('locationNameValue').textContent = r.location_name;
            } catch(e) { warn('geocode error:', e); }
        }, 30000);
    }

    function stopSendInterval() {
        if (sendIntervalId !== null) {
            clearInterval(sendIntervalId);
            sendIntervalId = null;
        }
        if (geocodeIntervalId !== null) {
            clearInterval(geocodeIntervalId);
            geocodeIntervalId = null;
        }
        tickBusy = false;
        log('sendInterval stopped');
    }

    // startWatchingPosition / stopWatchingPosition kept as no-ops
    // so call-sites in applyServerState / stopTracking still work.
    function startWatchingPosition() {}
    function stopWatchingPosition() {}

    const tickTimer = () => {
        const el = $('takingTimeValue');
        if (el && state.trackingStart)
            el.textContent = formatDuration(Date.now() - state.trackingStart);
    };

    // ── Apply server state to this tab's UI ───────────────
    // Called both on initial load and after every status poll.
    function applyServerState(serverIsTracking, firstLoad) {
        const wasTracking = state.tracking;
        state.tracking = serverIsTracking;

        if (serverIsTracking && !wasTracking && !firstLoad) {
            // Server flipped ON while page was open (another tab started) — sync UI
            log('applyServerState: sync ON');
            setStartBtn(true);
            setStopBtn(false);
            if (!state.timerIntervalId) {
                state.trackingStart = state.trackingStart || Date.now();
                state.timerIntervalId = setInterval(tickTimer, 1000);
            }
            // Do NOT start GPS here for cross-tab sync — only the tab that pressed Start owns GPS.
            updateStatusMessage('Tracking Active — Location updates every 2 seconds', 'info');

        } else if (!serverIsTracking && wasTracking) {
            // Server says tracking is OFF — sync this tab (another tab stopped it)
            log('applyServerState: sync OFF (firstLoad=%s)', firstLoad);
            setStartBtn(false);
            setStopBtn(true);
            clearInterval(state.timerIntervalId);
            state.timerIntervalId = null;
            state.trackingStart = null;
            if (isOwner) { stopWatchingPosition(); stopSendInterval(); }
            updateStatusMessage('Offline — Press Start to begin tracking', 'warning');

        } else if (firstLoad && serverIsTracking) {
            // Page opened while tracking already active in another tab/device.
            // Show active UI but NEVER auto-start GPS — only the original tab sends.
            log('applyServerState: firstLoad already-active — UI-only, no GPS');
            setStartBtn(true);
            setStopBtn(false);
            if (!state.timerIntervalId) {
                state.trackingStart = Date.now();
                state.timerIntervalId = setInterval(tickTimer, 1000);
            }
            updateStatusMessage('Tracking Active (another session running) — Location updates every 2 seconds', 'info');
            initLiveMap();

        } else if (firstLoad && !serverIsTracking) {
            // Fresh page load, not tracking → show clean state
            log('applyServerState: initial clean state');
            setStartBtn(false);
            setStopBtn(true);
            updateStatusMessage('Ready — Press Start to begin tracking', 'info');
            initLiveMap();
        }
    }

    // ── Cross-tab status polling ──────────────────────────
    // Polls every 2 s (tracking) / 5 s (idle).
    // If any tab calls Stop, all tabs detect the change here and halt GPS.
    async function pollStatus() {
        try {
            const res  = await fetch(`/salesperson_tracking/status/${trackerId}`);
            if (!res.ok) return;
            const data = await res.json();
            if (!data.ok) return;

            log('pollStatus: is_tracking=%s status=%s', data.is_tracking, data.status);

            applyServerState(data.is_tracking, false);

            // Update last-seen and location name shown on manager view
            if (!isOwner) {
                if (data.last_seen    && $('lastSeenValue'))    $('lastSeenValue').textContent    = data.last_seen;
                if (data.location_name && $('locationNameValue')) $('locationNameValue').textContent = data.location_name;
                if (data.last_lat && data.last_lng) {
                    if ($('latitudeValue'))  $('latitudeValue').textContent  = parseFloat(data.last_lat).toFixed(6);
                    if ($('longitudeValue')) $('longitudeValue').textContent = parseFloat(data.last_lng).toFixed(6);
                }
            }
        } catch(e) { warn('pollStatus error:', e); }
    }

    function schedulePollStatus() {
        // While tracking: poll every 10 s (only need to detect
        // stop from another tab — doTick handles the real work).
        // While stopped: poll every 5 s to detect start quickly.
        const interval = state.tracking ? 10000 : 5000;
        setTimeout(async () => { await pollStatus(); schedulePollStatus(); }, interval);
    }

    // Heartbeat replaced by sendTick (runs every 2 s)

    // ── Start button ──────────────────────────────────────
    const startTracking = async () => {
        if (state.tracking) { log('startTracking: already tracking — ignored'); return; }
        if (!navigator.geolocation) { updateStatusMessage('Geolocation not supported', 'error'); return; }

        log('startTracking: calling /start');
        setStartBtn(true);
        updateStatusMessage('Starting…', 'info');
        try {
            const result = await postJson('/salesperson_tracking/start', { tracker_id: trackerId });
            if (!result.ok) { warn('start failed:', result.error); setStartBtn(false); return; }
            log('startTracking: server responded ok, already_active=%s', result.already_active);
            state.trackingStart = Date.now();
            applyServerState(true, false);
            // This tab pressed Start — it owns GPS sending
            startWatchingPosition();
            startSendInterval();
        } catch(e) {
            err('startTracking error:', e);
            setStartBtn(false);
            updateStatusMessage('Failed to start: ' + e.message, 'error');
        }
    };

    // ── Stop button ───────────────────────────────────────
    const stopTracking = async () => {
        if (!state.tracking) { log('stopTracking: not tracking — ignored'); return; }

        log('stopTracking: calling /stop');
        setStopBtn(true);
        try {
            await postJson('/salesperson_tracking/stop', { tracker_id: trackerId });
            log('stopTracking: server responded ok');
            stopWatchingPosition();
            stopSendInterval();
            clearInterval(state.timerIntervalId);
            state.timerIntervalId = null;
            state.trackingStart = null;
            state.lastLat = state.lastLng = null;
            state.tracking = false;
            setStartBtn(false);
            setStopBtn(true);
            updateStatusMessage('Offline — Press Start to begin tracking', 'warning');
        } catch(e) {
            err('stopTracking error:', e);
            setStopBtn(false);
            updateStatusMessage('Failed to stop: ' + e.message, 'error');
        }
    };

    // ── Camera ────────────────────────────────────────────
    const cameraOverlay = $('cameraOverlay');
    const selfieVideo   = $('selfieVideo');
    const selfieCanvas  = $('selfieCanvas');
    let stream = null;

    async function openCamera() {
        try {
            stream = await navigator.mediaDevices.getUserMedia({ video: true });
            selfieVideo.srcObject = stream;
            cameraOverlay.style.display = 'flex';
        } catch(e) { updateStatusMessage('Camera access denied', 'error'); }
    }
    function closeCamera() {
        if (stream) { stream.getTracks().forEach(t => t.stop()); stream = null; }
        cameraOverlay.style.display = 'none';
    }
    async function capturePhoto() {
        const ctx = selfieCanvas.getContext('2d');
        selfieCanvas.width  = selfieVideo.videoWidth;
        selfieCanvas.height = selfieVideo.videoHeight;
        ctx.drawImage(selfieVideo, 0, 0);
        const imageData = selfieCanvas.toDataURL('image/jpeg', 0.8);
        try {
            const r = await fetch('/salesperson_tracking/save_photo', {
                method: 'POST', credentials: 'same-origin',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ image_data: imageData, filename: `photo_${Date.now()}.jpg` }),
            });
            const res = await r.json();
            if (res.ok) {
                const n = $('snapNotification');
                if (n) { n.style.display = 'block'; setTimeout(() => { n.style.display = 'none'; }, 2000); }
                closeCamera();
            }
        } catch(e) { updateStatusMessage('Failed to save photo', 'error'); }
    }

    // ── Manager polling (live location view) ──────────────
    const pollManagerView = async () => {
        if (isOwner) return;
        try {
            const res  = await fetch('/salesperson_tracking/moving_map_data/' + trackerId);
            const data = await res.json();
            if (!data.ok || !data.points || !data.points.length) return;

            if (!liveMap) initLiveMap();
            if (livePolyline) { liveMap.removeLayer(livePolyline); livePolyline = null; }
            if (liveMarker)   { liveMap.removeLayer(liveMarker);   liveMarker   = null; }

            livePath = data.points.map(p => [p.lat, p.lng]);
            if (livePath.length > 1)
                livePolyline = L.polyline(livePath, { color: '#3b82f6', weight: 4 }).addTo(liveMap);

            const last = data.points[data.points.length - 1];
            liveMarker = L.circleMarker([last.lat, last.lng], {
                radius: 10, color: '#fff', fillColor: '#ef4444', fillOpacity: 1, weight: 3,
            }).bindTooltip(data.last_seen || '').addTo(liveMap);

            // No auto-pan; manager controls their own view
            setTimeout(() => liveMap.invalidateSize(), 100);

            if ($('latitudeValue'))  $('latitudeValue').textContent  = parseFloat(last.lat).toFixed(6);
            if ($('longitudeValue')) $('longitudeValue').textContent = parseFloat(last.lng).toFixed(6);
            if ($('kpiDistance') && data.total_distance_km != null)
                $('kpiDistance').textContent = parseFloat(data.total_distance_km).toFixed(1);
        } catch(e) { warn('pollManagerView error:', e); }
    };

    // ── Boot ──────────────────────────────────────────────
    // Read the DB state the server rendered into data attributes.
    const serverIsTracking = root.dataset.isTracking === '1';
    log('Boot: isOwner=%s trackerId=%s serverIsTracking=%s', isOwner, trackerId, serverIsTracking);

    if (isOwner) {
        const startBtn       = $('startButton');
        const stopBtn        = $('stopButton');
        const openCameraBtn  = $('openCameraBtn');
        const captureBtn     = $('captureBtn');
        const closeCameraBtn = $('closeCameraBtn');

        if (startBtn)      startBtn.addEventListener('click', startTracking);
        if (stopBtn)       stopBtn.addEventListener('click', stopTracking);
        if (openCameraBtn) openCameraBtn.addEventListener('click', openCamera);
        if (captureBtn)    captureBtn.addEventListener('click', capturePhoto);
        if (closeCameraBtn) closeCameraBtn.addEventListener('click', closeCamera);

        // Issue 5: NEVER auto-start — always show clean map until user presses Start.
        // applyServerState handles UI-only sync without starting GPS automatically.
        applyServerState(serverIsTracking, true);

    } else {
        // Manager/viewer
        initLiveMap();
        pollManagerView();
        setInterval(pollManagerView, 3000);
        updateStatusMessage("Viewing salesperson's live location — auto-updates every 3 seconds", 'info');
    }

    // Cross-tab sync polling (both owner and manager benefit)
    schedulePollStatus();
})();


(function() {
    'use strict';

    // ── Debug logger ──────────────────────────────────────────
    const DEBUG = true;
    const log  = DEBUG ? (...a) => console.log('[MovingMap]', ...a) : () => {};
    const warn = (...a) => console.warn('[MovingMap]', ...a);
    const err  = (...a) => console.error('[MovingMap]', ...a);

    const mapRoot    = document.getElementById('mapRoot');
    const pointsB64  = mapRoot.getAttribute('data-points')    || '';
    const custB64    = mapRoot.getAttribute('data-customers') || '';
    const initStatus = mapRoot.getAttribute('data-status')    || 'offline';
    const trackerId  = parseInt(mapRoot.getAttribute('data-tracker-id') || '0', 10);

    let points    = [];
    let customers = [];
    try { points    = JSON.parse(atob(pointsB64)); } catch(e) { warn('points parse error', e); }
    try { customers = JSON.parse(atob(custB64)); }   catch(e) { warn('customers parse error', e); }

    log('Init — trackerId=%d initStatus=%s points=%d customers=%d',
        trackerId, initStatus, points.length, customers.length);

    // ── Map init ──────────────────────────────────────────────
    const map = L.map('map').setView([23.7701, 90.4254], 13);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
        attribution: '© OpenStreetMap contributors',
    }).addTo(map);

    // Customer layer rendered FIRST → sits below path and salesperson marker
    const customerLayer = L.layerGroup().addTo(map);

    let trackPolylines = [];
    let reconnectLines = [];
    let startMarker    = null;
    let currentMarker  = null;
    let allLatLngs     = [];

    // ── Helpers ───────────────────────────────────────────────
    function calcDistKm(pts) {
        const R = 6371; let d = 0;
        for (let i = 1; i < pts.length; i++) {
            const dLat = (pts[i].lat - pts[i-1].lat) * Math.PI / 180;
            const dLng = (pts[i].lng - pts[i-1].lng) * Math.PI / 180;
            const a = Math.sin(dLat/2)**2
                    + Math.cos(pts[i-1].lat * Math.PI/180)
                    * Math.cos(pts[i].lat * Math.PI/180)
                    * Math.sin(dLng/2)**2;
            d += R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
        }
        return d;
    }

    function updateStats(pts) {
        document.getElementById('distanceVal').textContent = calcDistKm(pts).toFixed(2) + ' km';
        document.getElementById('pointsVal').textContent   = pts.length;
        document.getElementById('logCount').textContent    = pts.length;
    }

    // Fix 2: only live / offline — no idle
    function updateStatus(status, label) {
        // Treat any truthy is_tracking as "live"
        const resolved = (status === 'live') ? 'live' : 'offline';
        const badge = document.getElementById('statusBadge');
        const dot   = badge ? badge.querySelector('.status-dot') : null;
        const lbl   = document.getElementById('statusLabel');
        if (badge) badge.className = 'status-pill ' + resolved;
        if (dot)   dot.className   = 'status-dot '  + resolved;
        if (lbl)   lbl.textContent = resolved === 'live' ? 'Live' : 'Offline';
        log('Status updated → %s', resolved);
    }

    // ── Fix 1: Parse localized time string for gap detection ──
    // Server sends "2026-05-12 14:39:58" (localized). JS Date needs ISO:
    function parseTime(t) {
        if (!t) return 0;
        // Replace space with T; add Z only if no offset present
        const iso = t.trim().replace(' ', 'T');
        const ms  = new Date(iso).getTime();
        return isNaN(ms) ? 0 : ms;
    }

    // ── OSRM reconnect route ──────────────────────────────────
    async function osrmRoute(fromPt, toPt) {
        try {
            const url = `https://router.project-osrm.org/route/v1/driving/`
                      + `${fromPt.lng},${fromPt.lat};${toPt.lng},${toPt.lat}`
                      + `?overview=full&geometries=geojson`;
            const res  = await fetch(url, { signal: AbortSignal.timeout(5000) });
            const data = await res.json();
            if (data.code === 'Ok' && data.routes?.[0]) {
                return data.routes[0].geometry.coordinates.map(([lng, lat]) => ({ lat, lng }));
            }
        } catch(e) { warn('OSRM failed, using straight line:', e); }
        return [fromPt, toPt];
    }

    const GAP_SECONDS = 120;

    function splitIntoSegments(pts) {
        if (!pts.length) return [];
        const segs = []; let cur = [pts[0]];
        for (let i = 1; i < pts.length; i++) {
            const dt = (parseTime(pts[i].time) - parseTime(pts[i-1].time)) / 1000;
            if (dt > GAP_SECONDS) {
                log('Gap at [%d→%d]: %.0fs', i-1, i, dt);
                segs.push({ points: cur, reconnectTo: pts[i] });
                cur = [pts[i]];
            } else { cur.push(pts[i]); }
        }
        segs.push({ points: cur, reconnectTo: null });
        return segs;
    }

    // ── Fix 3+4: renderPath — correct marker sizes/colors, live path ──
    // Live (is_tracking=true)  → current pos marker is GREEN
    // Offline (stopped)        → current pos marker is RED
    // Path colour: blue (#3b82f6)
    // Visited customer: dark green (#15803d)
    // Planned (not yet visited): blue (#3b82f6)
    // Skipped: yellow (#eab308)
    async function renderPath(pts, isLive) {
        log('renderPath: %d points, isLive=%s', pts.length, isLive);

        trackPolylines.forEach(p => map.removeLayer(p));
        trackPolylines = [];
        reconnectLines.forEach(l => map.removeLayer(l));
        reconnectLines = [];
        if (startMarker)   { map.removeLayer(startMarker);   startMarker   = null; }
        if (currentMarker) { map.removeLayer(currentMarker); currentMarker = null; }

        if (!pts.length) { warn('renderPath: no points'); updateStats([]); return; }

        const segs = splitIntoSegments(pts);
        allLatLngs = pts.map(p => [p.lat, p.lng]);

        // ── Fix 4: draw path — blue polyline ─────────────────
        for (const seg of segs) {
            if (seg.points.length > 1) {
                const poly = L.polyline(
                    seg.points.map(p => [p.lat, p.lng]),
                    { color: '#3b82f6', weight: 4, opacity: 0.9 }
                ).addTo(map);
                trackPolylines.push(poly);
            }
            if (seg.reconnectTo) {
                const fromPt   = seg.points[seg.points.length - 1];
                const routePts = await osrmRoute(fromPt, seg.reconnectTo);
                const recoLine = L.polyline(
                    routePts.map(p => [p.lat, p.lng]),
                    { color: '#6366f1', weight: 2, opacity: 0.7, dashArray: '8, 6' }
                ).addTo(map);
                recoLine.bindTooltip('Reconnected (OSRM)', { sticky: true });
                reconnectLines.push(recoLine);
            }
        }

        // Start marker — small green dot
        startMarker = L.circleMarker([pts[0].lat, pts[0].lng], {
            radius: 5, color: '#fff', fillColor: '#22c55e', fillOpacity: 1, weight: 2,
            pane: 'markerPane',
        }).bindTooltip('Start').addTo(map);

        // ── Fix 3: Current position marker ───────────────────
        // Small (radius 8), green when live, red when offline
        const last        = pts[pts.length - 1];
        const markerColor = isLive ? '#22c55e' : '#ef4444';
        const tipLabel    = isLive ? '● Live' : '● Last seen';
        const tooltip     = `${tipLabel}${last.time ? '\n' + last.time : ''}${last.accuracy ? '\nAccuracy: ' + last.accuracy.toFixed(0) + ' m' : ''}`;

        currentMarker = L.circleMarker([last.lat, last.lng], {
            radius: 8, color: '#fff', fillColor: markerColor, fillOpacity: 1, weight: 2,
            pane: 'markerPane',
        }).bindTooltip(tooltip, { permanent: false, sticky: false }).addTo(map);

        if (currentMarker.bringToFront) currentMarker.bringToFront();

        log('renderPath: currentMarker lat=%.6f lng=%.6f color=%s', last.lat, last.lng, markerColor);

        updateStats(pts);

        // Fit bounds: path + all customer pins
        const custLL = customers.filter(c => c.lat && c.lng).map(c => [c.lat, c.lng]);
        const allBounds = [...allLatLngs, ...custLL];
        if (allBounds.length === 1) {
            map.setView(allBounds[0], 16);
        } else if (allBounds.length > 1) {
            map.fitBounds(L.latLngBounds(allBounds), { padding: [50, 50] });
        }
        setTimeout(() => map.invalidateSize(), 200);
    }

    // ── Fix 3: Customer pins — correct colors ─────────────────
    // visited  → dark green #15803d
    // planned  → blue       #3b82f6
    // (skipped would be yellow but we don't have that field yet → remains blue)
    function renderCustomers(custList) {
        customerLayer.clearLayers();
        let drawn = 0;
        custList.forEach(c => {
            if (!c.lat || !c.lng) { warn('Customer "%s" missing coords — skip', c.name); return; }
            const color   = c.visited ? '#15803d' : '#3b82f6';
            const label   = c.visited ? '✓ Visited' : '○ Planned';
            L.circleMarker([c.lat, c.lng], {
                radius: 8, color: '#fff', fillColor: color, fillOpacity: 0.9, weight: 2,
            })
            .bindPopup(`<b>${c.name}</b><br/>${label}`)
            .addTo(customerLayer);
            drawn++;
            log('Customer pin: "%s" lat=%.6f lng=%.6f color=%s', c.name, c.lat, c.lng, color);
        });
        log('renderCustomers: %d pins drawn', drawn);
    }

    // ── Initial render ────────────────────────────────────────
    const isLiveInit = initStatus === 'live';
    renderCustomers(customers);
    renderPath(points, isLiveInit);

    // ── Fix 4: Live polling — re-render on every new point ────
    let knownPointCount = points.length;
    let currentStatus   = initStatus;
    let currentIsLive   = isLiveInit;
    let pollErrors      = 0;

    async function pollMap() {
        try {
            const res  = await fetch(`/salesperson_tracking/moving_map_data/${trackerId}`);
            if (!res.ok) { warn('pollMap HTTP %d', res.status); pollErrors++; return; }
            const data = await res.json();
            if (!data.ok) { warn('pollMap ok=false', data); return; }
            pollErrors = 0;

            const newIsLive = !!data.is_tracking;
            const newStatus = newIsLive ? 'live' : 'offline';

            log('pollMap: status=%s points=%d last_lat=%s', newStatus, data.points.length, data.last_lat);

            const statusChanged = newStatus !== currentStatus;
            if (statusChanged) {
                currentStatus = newStatus;
                currentIsLive = newIsLive;
                updateStatus(newStatus, newIsLive ? 'Live' : 'Offline');
            }

            // Fix 4: re-render whenever point count changes (live movement)
            // Also re-render on status change so marker color updates
            if (data.points.length !== knownPointCount || statusChanged) {
                log('pollMap: re-rendering (was %d pts → %d pts, statusChanged=%s)',
                    knownPointCount, data.points.length, statusChanged);
                knownPointCount = data.points.length;
                await renderPath(data.points, newIsLive);
                if (currentMarker?.bringToFront) currentMarker.bringToFront();
            }
        } catch(e) {
            pollErrors++;
            err('pollMap error (consecutive=%d):', pollErrors, e);
        }
    }

    function schedulePoll() {
        // Poll every 2s when live (to catch each GPS fix), 10s when offline
        const interval = currentStatus === 'live' ? 2000 : 10000;
        setTimeout(async () => { await pollMap(); schedulePoll(); }, interval);
    }

    schedulePoll();
    log('Polling started. Status=%s interval=%s', currentStatus, currentStatus === 'live' ? '2s' : '10s');

})();
